1	import { createElement } from "react";
2	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
3	import { createRouter } from "@tanstack/react-router";
4	
5	import { routeTree } from "./routeTree.gen";
6	import { StoreProvider } from "./store";
7	
8	type RouterHistory = NonNullable<Parameters<typeof createRouter>[0]["history"]>;
9	
10	export function getRouter(history: RouterHistory) {
11	  const queryClient = new QueryClient();
12	
13	  return createRouter({
14	    routeTree,
15	    history,
16	    context: {
17	      queryClient,
18	    },
19	    Wrap: ({ children }) =>
20	      createElement(
21	        QueryClientProvider,
22	        { client: queryClient },
23	        createElement(StoreProvider, null, children),
24	      ),
25	  });
26	}
27	
28	export type AppRouter = ReturnType<typeof getRouter>;
29	
30	declare module "@tanstack/react-router" {
31	  interface Register {
32	    router: AppRouter;
33	  }
34	}
