import { useCallback, useEffect, useMemo, useSyncExternalStore } from "react";
import {
  getTheme,
  listThemes,
  THEME_COLOR_KEYS,
  type ThemeDefinition,
} from "@t3tools/shared/themes";

type ColorScheme = "light" | "dark" | "system";
type ThemeSnapshot = {
  colorScheme: ColorScheme;
  systemDark: boolean;
  customThemeId: string | null;
};

const COLOR_SCHEME_KEY = "t3code:theme";
const CUSTOM_THEME_KEY = "t3code:custom-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;
function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredColorScheme(): ColorScheme {
  const raw = localStorage.getItem(COLOR_SCHEME_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredCustomTheme(): string | null {
  const raw = localStorage.getItem(CUSTOM_THEME_KEY);
  if (raw && getTheme(raw)) return raw;
  return null;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyDarkClass(isDark: boolean) {
  document.documentElement.classList.toggle("dark", isDark);
}

/** Inject or remove inline CSS custom-property overrides on `<html>`. */
function applyCustomThemeStyles(themeId: string | null) {
  const style = document.documentElement.style;
  const theme = themeId ? getTheme(themeId) : undefined;

  if (!theme || theme.cssManaged) {
    // Remove all inline overrides – let CSS cascade handle it
    for (const key of THEME_COLOR_KEYS) {
      style.removeProperty(`--${key}`);
    }
    style.removeProperty("font-family");
    style.removeProperty("font-size");
    return;
  }

  for (const key of THEME_COLOR_KEYS) {
    style.setProperty(`--${key}`, theme.colors[key]);
  }
}

function applyTheme(colorScheme: ColorScheme, customThemeId: string | null, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const customTheme = customThemeId ? getTheme(customThemeId) : undefined;

  // Resolve the effective light/dark state
  let isDark: boolean;
  if (customTheme) {
    isDark = customTheme.colorScheme === "dark";
  } else {
    isDark = colorScheme === "dark" || (colorScheme === "system" && getSystemDark());
  }
  applyDarkClass(isDark);

  // Inject or remove custom theme CSS overrides
  applyCustomThemeStyles(customThemeId);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredColorScheme(), getStoredCustomTheme());

// ---------------------------------------------------------------------------
// Snapshot / subscribe for useSyncExternalStore
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const colorScheme = getStoredColorScheme();
  const systemDark = colorScheme === "system" ? getSystemDark() : false;
  const customThemeId = getStoredCustomTheme();

  if (
    lastSnapshot &&
    lastSnapshot.colorScheme === colorScheme &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.customThemeId === customThemeId
  ) {
    return lastSnapshot;
  }

