import { describe, expect, it } from "vitest";
import { getTheme, listThemes, THEME_COLOR_KEYS, type ThemeColors } from "./themes";

describe("listThemes", () => {
  it("returns at least 3 built-in themes", () => {
    expect(listThemes().length).toBeGreaterThanOrEqual(3);
  });

  it("includes t3-dark, t3-light, and t3-midnight", () => {
    const ids = listThemes().map((t) => t.id);
    expect(ids).toContain("t3-dark");
    expect(ids).toContain("t3-light");
    expect(ids).toContain("t3-midnight");
  });

  it("every theme has a valid colorScheme", () => {
    for (const theme of listThemes()) {
      expect(["light", "dark"]).toContain(theme.colorScheme);
    }
  });

  it("every theme has non-empty fontFamily and fontSize", () => {
    for (const theme of listThemes()) {
      expect(theme.fontFamily.length).toBeGreaterThan(0);
      expect(theme.fontSize.length).toBeGreaterThan(0);
    }
  });

  it("every theme has non-empty background, foreground, and accent", () => {
    for (const theme of listThemes()) {
      expect(theme.colors.background.length).toBeGreaterThan(0);
      expect(theme.colors.foreground.length).toBeGreaterThan(0);
      expect(theme.colors.accent.length).toBeGreaterThan(0);
    }
  });
});

describe("getTheme", () => {
  it("returns the theme for a known id", () => {
    const theme = getTheme("t3-midnight");
    expect(theme).toBeDefined();
    expect(theme!.name).toBe("Midnight");
  });

  it("returns undefined for an unknown id", () => {
    expect(getTheme("nonexistent")).toBeUndefined();
  });

  it("returns the same reference as listThemes", () => {
    const all = listThemes();
    for (const theme of all) {
      expect(getTheme(theme.id)).toBe(theme);
    }
  });
});

describe("THEME_COLOR_KEYS", () => {
  it("matches the keys of ThemeColors", () => {
    const sampleTheme = getTheme("t3-dark");
    expect(sampleTheme).toBeDefined();
    const colorKeys = Object.keys(sampleTheme!.colors) as Array<keyof ThemeColors>;
    expect([...THEME_COLOR_KEYS].sort()).toEqual([...colorKeys].sort());
  });
});

