/**
 * Theme definitions for T3 Code.
 *
 * Pure data module — no DOM, no Effect, no Node.js APIs.
 * Each theme specifies every CSS custom property the app consumes so that
 * the web layer can inject them as inline styles on `<html>`.
 *
 * Themes whose colors are already expressed by the CSS cascade (light / dark)
 * are marked `cssManaged: true`. Their `colors` are still populated with
 * representative hex values for swatch previews, but the app layer skips
 * inline injection for them.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Every CSS custom property token a theme must provide. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly card: string;
  readonly "card-foreground": string;
  readonly popover: string;
  readonly "popover-foreground": string;
  readonly primary: string;
  readonly "primary-foreground": string;
  readonly secondary: string;
  readonly "secondary-foreground": string;
  readonly muted: string;
  readonly "muted-foreground": string;
  readonly accent: string;
  readonly "accent-foreground": string;
  readonly destructive: string;
  readonly "destructive-foreground": string;
  readonly border: string;
  readonly input: string;
  readonly ring: string;
  readonly info: string;
  readonly "info-foreground": string;
  readonly success: string;
  readonly "success-foreground": string;
  readonly warning: string;
  readonly "warning-foreground": string;
  readonly sidebar: string;
  readonly "sidebar-foreground": string;
  readonly editor: string;
  readonly "editor-foreground": string;
  readonly terminal: string;
  readonly "terminal-foreground": string;
  readonly "status-bar": string;
  readonly "status-bar-foreground": string;
}

export interface ThemeDefinition {
  readonly id: string;
  readonly name: string;
  /** Base color scheme — determines `.dark` class and `color-scheme`. */
  readonly colorScheme: "light" | "dark";
  /**
   * When `true`, the CSS cascade already provides the correct values and the
   * app layer should **not** inject inline custom-property overrides.
   * Swatch previews still use `colors`.
   */
  readonly cssManaged: boolean;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: string;
}

// ---------------------------------------------------------------------------
// Iterable key list (single source of truth)
// ---------------------------------------------------------------------------

/** All CSS custom property keys a theme can override. */
export const THEME_COLOR_KEYS: ReadonlyArray<keyof ThemeColors> = [
  "background",
  "foreground",
  "card",
  "card-foreground",
  "popover",
  "popover-foreground",
  "primary",
  "primary-foreground",
  "secondary",
  "secondary-foreground",
  "muted",
  "muted-foreground",
  "accent",
  "accent-foreground",
  "destructive",
  "destructive-foreground",
  "border",
  "input",
  "ring",
  "info",
  "info-foreground",
  "success",
  "success-foreground",
  "warning",
  "warning-foreground",
  "sidebar",
  "sidebar-foreground",
  "editor",
  "editor-foreground",
  "terminal",
  "terminal-foreground",
  "status-bar",
  "status-bar-foreground",
] as const;

// ---------------------------------------------------------------------------
// Font stacks
// ---------------------------------------------------------------------------

const SANS_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';
const DEFAULT_FONT_SIZE = "14px";

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const t3Light: ThemeDefinition = {
  id: "t3-light",
  name: "Light",
  colorScheme: "light",
  cssManaged: true,
  fontFamily: SANS_FONT_FAMILY,
  fontSize: DEFAULT_FONT_SIZE,
  colors: {
    background: "#ffffff",
    foreground: "#1e293b",
    card: "#ffffff",
    "card-foreground": "#1e293b",
    popover: "#ffffff",
    "popover-foreground": "#1e293b",
    primary: "#4f46e5",
    "primary-foreground": "#ffffff",
    secondary: "rgba(0,0,0,0.04)",
    "secondary-foreground": "#1e293b",
    muted: "rgba(0,0,0,0.04)",
    "muted-foreground": "#64748b",
    accent: "rgba(0,0,0,0.04)",
    "accent-foreground": "#1e293b",
    destructive: "#ef4444",
    "destructive-foreground": "#b91c1c",
    border: "rgba(0,0,0,0.08)",
    input: "rgba(0,0,0,0.10)",
    ring: "#4f46e5",
    info: "#3b82f6",
    "info-foreground": "#1d4ed8",
    success: "#10b981",
    "success-foreground": "#047857",
    warning: "#f59e0b",
    "warning-foreground": "#b45309",
    sidebar: "#ffffff",
    "sidebar-foreground": "#1e293b",
    editor: "#ffffff",
    "editor-foreground": "#1e293b",
    terminal: "#ffffff",
    "terminal-foreground": "#1e293b",
    "status-bar": "#ffffff",
    "status-bar-foreground": "#1e293b",
  },
};

const t3Dark: ThemeDefinition = {
  id: "t3-dark",
  name: "Dark",
  colorScheme: "dark",
  cssManaged: true,
  fontFamily: SANS_FONT_FAMILY,
  fontSize: DEFAULT_FONT_SIZE,
  colors: {
    background: "#0c0c0e",
    foreground: "#f1f5f9",
    card: "#111114",
    "card-foreground": "#f1f5f9",
    popover: "#111114",
    "popover-foreground": "#f1f5f9",
    primary: "#6366f1",
    "primary-foreground": "#ffffff",
    secondary: "rgba(255,255,255,0.04)",
    "secondary-foreground": "#f1f5f9",
    muted: "rgba(255,255,255,0.04)",
    "muted-foreground": "#94a3b8",
    accent: "rgba(255,255,255,0.04)",
    "accent-foreground": "#f1f5f9",
    destructive: "#f87171",
    "destructive-foreground": "#fca5a5",
    border: "rgba(255,255,255,0.06)",
    input: "rgba(255,255,255,0.08)",
    ring: "#6366f1",
    info: "#3b82f6",
    "info-foreground": "#60a5fa",
    success: "#10b981",
    "success-foreground": "#34d399",
    warning: "#f59e0b",
    "warning-foreground": "#fbbf24",
    sidebar: "#111114",
    "sidebar-foreground": "#f1f5f9",
    editor: "#0c0c0e",
    "editor-foreground": "#f1f5f9",
    terminal: "#0c0c0e",
    "terminal-foreground": "#f1f5f9",
    "status-bar": "#111114",
    "status-bar-foreground": "#f1f5f9",
  },
};

const t3Midnight: ThemeDefinition = {
  id: "t3-midnight",
  name: "Midnight",
  colorScheme: "dark",
  cssManaged: false,
  fontFamily: SANS_FONT_FAMILY,
  fontSize: DEFAULT_FONT_SIZE,
  colors: {
    background: "#080810",
    foreground: "#e2e8f0",
    card: "#0e0e1a",
    "card-foreground": "#e2e8f0",
    popover: "#0e0e1a",
    "popover-foreground": "#e2e8f0",
    primary: "#818cf8",
    "primary-foreground": "#ffffff",
    secondary: "rgba(150,160,255,0.06)",
    "secondary-foreground": "#e2e8f0",
    muted: "rgba(150,160,255,0.06)",
    "muted-foreground": "#7c85a6",
    accent: "rgba(150,160,255,0.08)",
    "accent-foreground": "#e2e8f0",
    destructive: "#f87171",
    "destructive-foreground": "#fca5a5",
    border: "rgba(130,140,220,0.10)",
    input: "rgba(130,140,220,0.12)",
    ring: "#818cf8",
    info: "#60a5fa",
    "info-foreground": "#93c5fd",
    success: "#34d399",
    "success-foreground": "#6ee7b7",
    warning: "#fbbf24",
    "warning-foreground": "#fcd34d",
    sidebar: "#0a0a16",
    "sidebar-foreground": "#e2e8f0",
    editor: "#080810",
    "editor-foreground": "#e2e8f0",
    terminal: "#06060e",
    "terminal-foreground": "#e2e8f0",
    "status-bar": "#0e0e1a",
    "status-bar-foreground": "#e2e8f0",
  },
};

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

const BUILT_IN_THEMES: readonly ThemeDefinition[] = [t3Dark, t3Light, t3Midnight];

const THEMES_BY_ID = new Map<string, ThemeDefinition>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Return every available theme. */
export function listThemes(): readonly ThemeDefinition[] {
  return BUILT_IN_THEMES;
}

/** Look up a theme by id. Returns `undefined` for unknown ids. */
export function getTheme(id: string): ThemeDefinition | undefined {
  return THEMES_BY_ID.get(id);
}

