import { useCallback, useEffect, useMemo, useSyncExternalStore } from "react";
import {
  getTheme,
  listThemes,
  THEME_COLOR_KEYS,
  type ThemeDefinition,
} from "@t3tools/shared/themes";

type ColorScheme = "light" | "dark" | "system";
type ThemeSnapshot = {
  colorScheme: ColorScheme;
  systemDark: boolean;
  customThemeId: string | null;
};

const COLOR_SCHEME_KEY = "t3code:theme";
const CUSTOM_THEME_KEY = "t3code:custom-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;
function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredColorScheme(): ColorScheme {
  const raw = localStorage.getItem(COLOR_SCHEME_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredCustomTheme(): string | null {
  const raw = localStorage.getItem(CUSTOM_THEME_KEY);
  if (raw && getTheme(raw)) return raw;
  return null;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyDarkClass(isDark: boolean) {
  document.documentElement.classList.toggle("dark", isDark);
}

/** Inject or remove inline CSS custom-property overrides on `<html>`. */
function applyCustomThemeStyles(themeId: string | null) {
  const style = document.documentElement.style;
  const theme = themeId ? getTheme(themeId) : undefined;

  if (!theme || theme.cssManaged) {
    // Remove all inline overrides – let CSS cascade handle it
    for (const key of THEME_COLOR_KEYS) {
      style.removeProperty(`--${key}`);
    }
    style.removeProperty("font-family");
    style.removeProperty("font-size");
    return;
  }

  for (const key of THEME_COLOR_KEYS) {
    style.setProperty(`--${key}`, theme.colors[key]);
  }
}

function applyTheme(colorScheme: ColorScheme, customThemeId: string | null, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const customTheme = customThemeId ? getTheme(customThemeId) : undefined;

  // Resolve the effective light/dark state
  let isDark: boolean;
  if (customTheme) {
    isDark = customTheme.colorScheme === "dark";
  } else {
    isDark = colorScheme === "dark" || (colorScheme === "system" && getSystemDark());
  }
  applyDarkClass(isDark);

  // Inject or remove custom theme CSS overrides
  applyCustomThemeStyles(customThemeId);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredColorScheme(), getStoredCustomTheme());

// ---------------------------------------------------------------------------
// Snapshot / subscribe for useSyncExternalStore
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const colorScheme = getStoredColorScheme();
  const systemDark = colorScheme === "system" ? getSystemDark() : false;
  const customThemeId = getStoredCustomTheme();

  if (
    lastSnapshot &&
    lastSnapshot.colorScheme === colorScheme &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.customThemeId === customThemeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { colorScheme, systemDark, customThemeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    const stored = getStoredColorScheme();
    const customThemeId = getStoredCustomTheme();
    if (stored === "system" && !customThemeId) {
      applyTheme(stored, null, true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_SCHEME_KEY || e.key === CUSTOM_THEME_KEY) {
      applyTheme(getStoredColorScheme(), getStoredCustomTheme(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const colorScheme = snapshot.colorScheme;
  const customThemeId = snapshot.customThemeId;
  const customTheme = customThemeId ? getTheme(customThemeId) : undefined;

  const resolvedTheme: "light" | "dark" = customTheme
    ? customTheme.colorScheme
    : colorScheme === "system"
      ? snapshot.systemDark
        ? "dark"
        : "light"
      : colorScheme;

  // Backward-compatible: existing callers use `theme` for the "light"|"dark"|"system" value
  const theme = colorScheme;

  const setTheme = useCallback((next: ColorScheme) => {
    localStorage.setItem(COLOR_SCHEME_KEY, next);
    // Switching the color-scheme toggle clears any active custom theme
    localStorage.removeItem(CUSTOM_THEME_KEY);
    applyTheme(next, null, true);
    emitChange();
  }, []);

  const setCustomTheme = useCallback((id: string | null) => {
    if (id === null) {
      localStorage.removeItem(CUSTOM_THEME_KEY);
      applyTheme(getStoredColorScheme(), null, true);
    } else {
      const themeDef = getTheme(id);
      if (!themeDef) return;
      localStorage.setItem(CUSTOM_THEME_KEY, id);
      // Align the color scheme to the theme's base so resolvedTheme is correct
      localStorage.setItem(COLOR_SCHEME_KEY, themeDef.colorScheme);
      applyTheme(themeDef.colorScheme, id, true);
    }
    emitChange();
  }, []);

  const availableThemes: readonly ThemeDefinition[] = useMemo(() => listThemes(), []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(colorScheme, customThemeId);
  }, [colorScheme, customThemeId]);

  return {
    /** The stored color-scheme preference: "light" | "dark" | "system". */
    theme,
    /** Set the color-scheme toggle. Clears any active custom theme. */
    setTheme,
    /** The resolved light/dark value (accounts for system preference and custom theme). */
    resolvedTheme,
    /** The active custom theme id, or `null` when using the default light/dark cascade. */
    customThemeId,
    /** Activate a custom theme by id, or pass `null` to clear. */
    setCustomTheme,
    /** All available theme definitions. */
    availableThemes,
  } as const;
}

