import type { ThemeDefinition } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";
import { cn } from "~/lib/utils";

function ThemeSwatch({
  theme,
  selected,
  onSelect,
}: {
  theme: ThemeDefinition;
  selected: boolean;
  onSelect: () => void;
}) {
  const { colors } = theme;

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={theme.name}
      className={cn(
        "flex flex-col gap-2 rounded-lg border p-3 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onSelect}
    >
      {/* Mini preview swatch */}
      <div
        className="flex h-14 w-full overflow-hidden rounded-md border"
        style={{
          backgroundColor: colors.background,
          borderColor: colors.border,
        }}
      >
        {/* Sidebar region */}
        <div
          className="flex w-6 shrink-0 flex-col gap-1 p-1"
          style={{ backgroundColor: colors.sidebar }}
        >
          <div
            className="h-1 w-full rounded-full"
            style={{ backgroundColor: colors.primary }}
          />
          <div
            className="h-1 w-full rounded-full opacity-40"
            style={{ backgroundColor: colors["sidebar-foreground"] }}
          />
          <div
            className="h-1 w-full rounded-full opacity-40"
            style={{ backgroundColor: colors["sidebar-foreground"] }}
          />
        </div>

        {/* Main editor region */}
        <div className="flex flex-1 flex-col">
          <div
            className="flex flex-1 flex-col justify-center gap-1 px-2 py-1"
            style={{ backgroundColor: colors.editor }}
          >
            <div
              className="h-1 w-4/5 rounded-full opacity-60"
              style={{ backgroundColor: colors["editor-foreground"] }}
            />
            <div
              className="h-1 w-3/5 rounded-full opacity-40"
              style={{ backgroundColor: colors["editor-foreground"] }}
            />
            <div
              className="h-1 w-2/3 rounded-full opacity-50"
              style={{ backgroundColor: colors["editor-foreground"] }}
            />
          </div>

          {/* Status bar */}
          <div
            className="flex h-2.5 items-center px-1"
            style={{ backgroundColor: colors["status-bar"] }}
          >
            <div
              className="h-1 w-4 rounded-full"
              style={{ backgroundColor: colors.primary, opacity: 0.7 }}
            />
          </div>
        </div>
      </div>

      {/* Label row */}
      <div className="flex items-center justify-between gap-2">
        <span className="text-xs font-medium">{theme.name}</span>
        {selected ? (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

export function ThemeSelector() {
  const { customThemeId, setCustomTheme, availableThemes, resolvedTheme } = useTheme();

  // Determine which theme is "selected":
  // - if a custom theme is active, match by id
  // - otherwise, match the CSS-managed theme that corresponds to resolvedTheme
  const activeId =
    customThemeId ??
    (resolvedTheme === "dark" ? "t3-dark" : "t3-light");

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((theme) => (
        <ThemeSwatch
          key={theme.id}
          theme={theme}
          selected={theme.id === activeId}
          onSelect={() => setCustomTheme(theme.id)}
        />
      ))}
    </div>
  );
}
